#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int countTargetSumExpressions(int *numbers, int n, int target){
    int total=0;
    for(int i=0;i<n;++i) total+=numbers[i];
    if(total<abs(target) || ((total+target)&1)) return 0;
    int subset=(total+target)/2;
    int *dp=calloc(subset+1,sizeof(int));
    dp[0]=1;
    for(int i=0;i<n;++i){
        int val=numbers[i];
        for(int s=subset;s>=val;--s) dp[s]+=dp[s-val];
    }
    int ans=dp[subset];
    free(dp);
    return ans;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *arr=malloc(N*sizeof(int));
        for(int i=0;i<N;++i) scanf("%d",&arr[i]);
        int target; scanf("%d",&target);
        printf("%d\n",countTargetSumExpressions(arr,N,target));
        free(arr);
    }
    return 0;
}

