int countTargetSumExpressions(const vector<int>& nums,int target){
    int total=accumulate(nums.begin(),nums.end(),0);
    if(total<abs(target) || ((total+target)&1)) return 0;
    int subset=(total+target)/2;
    vector<int> dp(subset+1,0);
    dp[0]=1;
    for(int x:nums){
        for(int s=subset;s>=x;--s) dp[s]+=dp[s-x];
    }
    return dp[subset];
}

