import java.util.*;

public class Main {
    private static int countTargetSumExpressions(int[] nums,int target){
        int total=0;
        for(int v:nums) total+=v;
        if(total<Math.abs(target) || ((total+target)&1)==1) return 0;
        int subset=(total+target)/2;
        int[] dp=new int[subset+1];
        dp[0]=1;
        for(int x:nums){
            for(int s=subset;s>=x;--s) dp[s]+=dp[s-x];
        }
        return dp[subset];
    }
    public static void main(String[] args){
        Scanner sc=new Scanner(System.in);
        int T=sc.nextInt();
        while(T-- > 0){
            int N=sc.nextInt();
            int[] arr=new int[N];
            for(int i=0;i<N;++i) arr[i]=sc.nextInt();
            int target=sc.nextInt();
            System.out.println(countTargetSumExpressions(arr,target));
        }
